/// this if for outbound order landed cost module
/// </summary>
[ExtensionOf(classStr(TradeLineNumberManager))]
internal final class ETGTradeLineNumberManager_Extension
{
}

Method.Source:
/// <summary>
/// get last line number and set last line number
/// </summary>
public void ETGOTMsetLastLineNumber()
{
    lastLineNumber = 0;
    TradeLineNumber lastNumberLocal = this.getLastLineNumber();

    if (lineNumbering.LineNumber != lastNumberLocal)
    {
        lineNumbering.LineNumber = lastNumberLocal + this.getIncrement();
    }
}
